() => {
  const anchor = document.querySelector('otto-web-tool-bar-toggle-button:has(gs-icon[aria-label="cloud_upload"])');
  if (!anchor) return;

  const center = anchor.parentElement;
  if (!center) return;

  center.querySelectorAll('otto-web-tool-bar-toggle-button').forEach((node) => {
    if (node !== anchor) {
      node.style.display = 'none';
    }
  });
}
